	sieve := make([]bool, n+1)

	for i := range sieve {
		sieve[i] = true
	}

	sieve[0] = false
	sieve[1] = false

	for i := 2; i*i <= n; i++ {
		if sieve[i] {
			for j := i * i; j <= n; j += i {
				sieve[j] = false
			}
		}
	}

	for i := 2; i <= n; i++ {
		if sieve[i] {
			primes = append(primes, i)
		}
	}

