func detectMime(data []byte) string {
	// This is a simple MIME type detection using the first few bytes
	// For a production environment, use a more sophisticated library
	if len(data) < 5 {
		return "application/octet-stream"
	}

	// Check for common MIME types
	if strings.HasPrefix(string(data[:5]), "image/") {
		return "image/*"
	} else if strings.HasPrefix(string(data[:5]), "text/") {
		return "text/*"
	} else if strings.HasPrefix(string(data[:5]), "application/") {
		return "application/*"
	}

	return "application/octet-stream"
}

