func analyzeTemperatureData(temperatures []float64) (float64, float64) {
	if len(temperatures) == 0 {
		return 0, 0
	}

	n := float64(len(temperatures))
	average := math.Sum(temperatures) / n

	var sumOfSquares float64
	for _, temp := range temperatures {
		sumOfSquares += math.Pow(temp, 2)
	}

	var variance float64
	variance = (sumOfSquares / n) - average * average

	stdDev := math.Sqrt(variance)

	return roundToTwoDecimals(average), roundToTwoDecimals(stdDev)
}

