func parseHttpResponse(res *http.Response) (int, string, bool) {
	// Check if the response is nil
	if res == nil {
		return 0, "", false
	}

	// Check status code
	statusCode := res.StatusCode
	statusMessage := res.Status

	// Check if status code is valid
	if statusCode < 100 || statusCode > 999 {
		return 0, "", false
	}

	// Check Cache-Control header
	cacheControl := res.Header.Get("Cache-Control")
	if cacheControl == "" {
		cacheControl = "no-cache"
	}

	// Determine cache policy
	cachePolicy := false
	if strings.Contains(cacheControl, "public") || strings.Contains(cacheControl, "private") || strings.Contains(cacheControl, "no-cache") {
		cachePolicy = true
	}

	return statusCode, statusMessage, cachePolicy
}

