func findMatchingFiles(directory string, pattern string) ([]string, int, error) {
	// Compile the regular expression
	re, err := regexp.Compile(pattern)
	if err != nil {
		return nil, 0, err
	}

	var matchedFiles []string
	count := 0

	// Walk through the directory
	err = filepath.Walk(directory, func(path string, info os.FileInfo) error {
		if !info.IsDir() {
			if re.MatchString(path) {
				matchedFiles = append(matchedFiles, path)
				count++
			}
		}
		return nil
	})

	if err != nil {
		return nil, 0, err
	}

	return matchedFiles, count, nil
}

