use std::collections::LinkedList;

fn manage_workflow(tasks: Vec<(String, String, String)>) -> (Vec<String>, HashMap<String, (String, String外, LinkedList<String>) {
    // 1. Sort tasks by deadline
    let sorted_tasks: Vec<String> = tasks
        .iter()
        .map(|&(task_id, _, deadline)| task_id)
        .collect::<Vec<_>>();
    sorted_tasks.sort_by(|&a, &b| {
        let deadline_a = &tasks.iter().find(|&&(task_id, _, deadline)| task_id == a).unwrap().1;
        let deadline_b = &tasks.iter().find(|&&(task_id, _, deadline)| task_id == b).unwrap().1;
        deadline_a.cmp(deadline_b)
    });

    // 2. Create HashMap with task ID as key and (owner, deadline) as value
    let mut task_map: HashMap<String, (String, String)> = HashMap::new();
    for (task_id, owner, deadline) in tasks {
        task_map.insert(task_id, (owner, deadline));
    }

    // 3. Create LinkedList of task IDs based on their order in the input
    let mut task_list: LinkedList<String> = LinkedList::new();
    for task_id in sorted_tasks {
        task_list.push_back(task_id);
    }

    (sorted_tasks, task_map, task_list)
}
