use std::collections::{BTreeMap, BTreeSet, VecDeque, ArrayVec};

#[derive(Debug, Clone, PartialEq)]
struct Transaction {
    account_id: String,
    amount: f64,
    type_: String, // "deposit" or "withdrawal"
}

fn manage_account_transactions(transactions: Vec<Transaction>) -> (VecDeque<Transaction>, BTreeMap<String, f64>, BTreeSet<String>, ArrayVec<(String, String)>> {
    let mut pending_transactions = VecDeque::new();
    let mut balances = BTreeMap::new();
    let mut suspicious_accounts = BTreeSet::new();
    let mut last_five_transactions = ArrayVec::new();

    for transaction in transactions {
        let account_id = transaction.account_id;
        let amount = transaction.amount;
        let type_ = transaction.type_.to_lowercase();

        // Check if transaction is valid
        if type_ != "deposit" && type_ != "withdrawal" {
            pending_transactions.push_back(transaction);
            continue;
        }

        // Validate balance for withdrawal
        if type_ == "withdrawal" {
            if let Some(balance) = balances.get_mut(&account_id) {
                if *balance < amount {
                    pending_transactions.push_back(transaction);
                } else {
                    *balance -= amount;
                }
            } else {
                pending_transactions.push_back(transaction);
            }
        } else { // deposit
            if let Some(balance) = balances.get_mut(&account_id) {
                *balance += amount;
            } else {
                balances.insert(account_id, amount);
            }
        }

        // Add to last five transactions
        if last_five_transactions.len() >= 5 {
            last_five_transactions.pop_front();
        }
        last_five_transactions.push_back((account_id, type_));
    }

    // Flag suspicious accounts
    for (account_id, _type) in last_five_transactions {
        if let Some(balance) = balances.get(&account_id) {
            if *balance > 1000.0 {
                suspicious_accounts.insert(account_id.clone());
            }
        }
    }

    (pending_transactions, balances, suspicious_accounts, last_five_transactions)
}
