use std::collections::HashSet;
use smallvec::SmallVec;

fn aggregate_sensor_data(sensor_data: Vec<(String, f64)>) -> (Vec<f64>, HashSet<String>, SmallVec<f64, 5>) {
    let mut readings: Vec<f64> = Vec::new();
    let mut unique_ids: HashSet<String> = HashSet::new();
    let mut buffer: SmallVec<f64, 5> = SmallVec::new();

    for (id, value) in sensor_data {
        readings.push(value);
        unique_ids.insert(id);
        buffer.push(value);
        if buffer.len() > 5 {
            buffer.pop();
        }
    }

    (readings, unique_ids, buffer)
}
