fn update_inventory(mut inventory: Vec<(String, i32)>) -> (HashMap<String, i32>, BTreeSet<String>, ArrayVec<(String, i32)>> {
    let mut inventory_map = HashMap::new();
    let mut out_of_stock = BTreeSet::new();
    let mut incoming = ArrayVec::new();

    for (product_id, quantity) in inventory {
        inventory_map.insert(product_id, inventory_map.get(&product_id).unwrap_or(&0) + quantity);
        if quantity < 0 {
            out_of_stock.insert(product_id.clone());
        }
        if quantity > 0 {
            incoming.push((product_id, quantity));
        }
    }

    (inventory_map, out_of_stock, incoming)
}

fn track_onboarding(users: Vec<(String, i32)>) -> (HashSet<String>, Vec<String>, LinkedList<String>) {
    let mut onboarding_complete = HashSet::new();
    let mut onboarding_order = Vec::new();
    let mut audit_trail = LinkedList::new();

    for (id, status) in users {
        onboarding_order.push(id.clone());
        audit_trail.push_back(id.clone());
        if status == 3 {
            onboarding_complete.insert(id.clone());
        }
    }

    (onboarding_complete, onboarding_order, audit_trail)
}
